export interface NseActiveSecurity {
  symbol: string;
  identifier: string;
  lastPrice: number;
  pChange: number;
  quantityTraded: number;
  totalTradedVolume: number;
  totalTradedValue: number;
  previousClose: number;
  yearHigh: number;
  yearLow: number;
  lastUpdateTime: string;
}

export interface NseActiveApiResponse {
  data: NseActiveSecurity[];
}

export interface PortfolioInsightItem {
  symbol: string;
  value: number; // Last Price
  change: number; // pChange
  insightText: string;
  type: 'positive' | 'negative' | 'neutral';
  category: string; // e.g., "Most Active", "Volume Spurt"
}

export interface PortfolioInsightCategory {
  id: string;
  title: string;
  items: PortfolioInsightItem[];
}

import { fetchFromProxy } from "./dataService";
import { NseActiveApiResponse, PortfolioInsightCategory, PortfolioInsightItem } from "../types/portfolioInsightsTypes";

// API Configurations
const INSIGHT_APIS = [
  {
    id: 'active_eq',
    title: 'Most Active Equities',
    url: 'https://www.nseindia.com/api/live-analysis-most-active-securities?index=value',
    type: 'VALUE'
  },
  {
    id: 'active_sme',
    title: 'Most Active SME',
    url: 'https://www.nseindia.com/api/live-analysis-most-active-sme?index=value',
    type: 'VALUE'
  }
];

const formatValue = (val: number) => {
    if (val >= 10000000) return (val / 10000000).toFixed(2) + 'Cr';
    if (val >= 100000) return (val / 100000).toFixed(2) + 'L';
    return val.toLocaleString();
};

export const fetchPortfolioInsights = async (): Promise<PortfolioInsightCategory[]> => {
  const promises = INSIGHT_APIS.map(async (config) => {
    try {
      const rawData = await fetchFromProxy(config.url);

      let jsonData: NseActiveApiResponse;
      if (typeof rawData === 'string') {
        try {
          jsonData = JSON.parse(rawData);
        } catch (e) {
          console.error(`Failed to parse JSON for ${config.id}`, e);
          return { id: config.id, title: config.title, items: [] };
        }
      } else {
        jsonData = rawData;
      }

      if (!jsonData || !jsonData.data || !Array.isArray(jsonData.data)) {
        return { id: config.id, title: config.title, items: [] };
      }

      const items: PortfolioInsightItem[] = jsonData.data.map(item => {
        const isPos = item.pChange >= 0;
        const type = Math.abs(item.pChange) < 0.5 ? 'neutral' : (isPos ? 'positive' : 'negative');

        let text = `${item.symbol} traded value ₹${formatValue(item.totalTradedValue)}. `;
        if (isPos) {
           text += `Up ${item.pChange}% from prev close.`;
        } else {
           text += `Down ${Math.abs(item.pChange)}% from prev close.`;
        }

        return {
          symbol: item.symbol,
          value: item.lastPrice,
          change: item.pChange,
          insightText: text,
          type: type,
          category: config.title
        };
      });

      return {
        id: config.id,
        title: config.title,
        items: items
      };

    } catch (e) {
      console.error(`Error fetching portfolio insight ${config.id}`, e);
      return { id: config.id, title: config.title, items: [] };
    }
  });

  return Promise.all(promises);
};

