  { id: 'PAYTM', name: 'One97 Communications Ltd', symbol: 'PAYTM', type: 'STOCK' },
  { id: 'RVNL', name: 'Rail Vikas Nigam Ltd', symbol: 'RVNL', type: 'STOCK' },
  { id: 'IRFC', name: 'Indian Railway Finance Corp', symbol: 'IRFC', type: 'STOCK' },
  { id: 'JIOFIN', name: 'Jio Financial Services', symbol: 'JIOFIN', type: 'STOCK' },
  { id: 'VBL', name: 'Varun Beverages Ltd', symbol: 'VBL', type: 'STOCK' },
  { id: 'HAL', name: 'Hindustan Aeronautics Ltd', symbol: 'HAL', type: 'STOCK' },
  { id: 'BEL', name: 'Bharat Electronics Ltd', symbol: 'BEL', type: 'STOCK' },
  { id: 'TRENT', name: 'Trent Ltd', symbol: 'TRENT', type: 'STOCK' },
  { id: 'MAZDOCK', name: 'Mazagon Dock Shipbuilders', symbol: 'MAZDOCK', type: 'STOCK' },
];

const DEFAULT_IGNORED_ITEMS: string[] = [
  "ADANIENSOL", "ADANIGREEN", "ADANITRANS", "POLICYBZR"
];

const DEFAULT_INDICES = ["NIFTY NEXT 50","NIFTY 50", "NIFTY BANK", "NIFTY IT"];

export const getTrackedItems = (): TrackedItem[] => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      return JSON.parse(stored);
    } else {
      // Initialize with defaults if empty
      localStorage.setItem(STORAGE_KEY, JSON.stringify(DEFAULT_ITEMS));
      return DEFAULT_ITEMS;
    }
  } catch (e) {
    console.error("Error parsing tracked items", e);
    return [];
  }
};

export const addTrackedItem = (item: TrackedItem) => {
  const items = getTrackedItems();
  // Prevent duplicates
  if (!items.find(i => i.id === item.id && i.type === item.type)) {
    const newItems = [...items, item];
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
    // Dispatch event to notify listeners (like Dashboard) to auto-refresh
    window.dispatchEvent(new Event(EVENT_KEY));
  }
};

export const removeTrackedItem = (id: string, type: EntityType) => {
  const items = getTrackedItems();
  const newItems = items.filter(i => !(i.id === id && i.type === type));
  localStorage.setItem(STORAGE_KEY, JSON.stringify(newItems));
  // Dispatch event to notify listeners
  window.dispatchEvent(new Event(EVENT_KEY));
};

export const isTracked = (id: string, type: EntityType): boolean => {
  const items = getTrackedItems();
  return !!items.find(i => i.id === id && i.type === type);
};

// --- Ignore List Logic ---

export const getIgnoredItems = (): string[] => {
  try {
    const stored = localStorage.getItem(IGNORED_KEY);
    if (stored) {
      return JSON.parse(stored);
    } else {
      localStorage.setItem(IGNORED_KEY, JSON.stringify(DEFAULT_IGNORED_ITEMS));
      return DEFAULT_IGNORED_ITEMS;
    }
  } catch (e) {
    console.error("Error parsing ignored items", e);
    return DEFAULT_IGNORED_ITEMS;
  }
};

export const addIgnoredItem = (symbol: string) => {
  const items = getIgnoredItems();
  if (!items.includes(symbol)) {
    const newItems = [...items, symbol];
    localStorage.setItem(IGNORED_KEY, JSON.stringify(newItems));
    window.dispatchEvent(new Event(EVENT_KEY));
  }
};

export const removeIgnoredItem = (symbol: string) => {
  const items = getIgnoredItems();
  const newItems = items.filter(i => i !== symbol);
  localStorage.setItem(IGNORED_KEY, JSON.stringify(newItems));
  window.dispatchEvent(new Event(EVENT_KEY));
};

export const isIgnored = (symbol: string): boolean => {
  const items = getIgnoredItems();
  return items.includes(symbol);
};

// --- Index Tracking Logic ---

export const getTrackedIndices = (): string[] => {
  try {
    const stored = localStorage.getItem(INDICES_KEY);
    if (stored) {
      return JSON.parse(stored);
    } else {
      localStorage.setItem(INDICES_KEY, JSON.stringify(DEFAULT_INDICES));
      return DEFAULT_INDICES;
    }
  } catch (e) {
    console.error("Error parsing tracked indices", e);
    return DEFAULT_INDICES;
  }
};

export const addTrackedIndex = (indexName: string) => {
  const indices = getTrackedIndices();
  if (!indices.includes(indexName)) {
    const newIndices = [...indices, indexName].sort();
    localStorage.setItem(INDICES_KEY, JSON.stringify(newIndices));
    window.dispatchEvent(new Event(EVENT_KEY));
  }
};

export const removeTrackedIndex = (indexName: string) => {
  const indices = getTrackedIndices();
  const newIndices = indices.filter(i => i !== indexName);
  localStorage.setItem(INDICES_KEY, JSON.stringify(newIndices));
  window.dispatchEvent(new Event(EVENT_KEY));
};

// Helper to generate the specific config for a stock
export const generateInsightConfig = (symbol: string, pk: string, slug: string): InsightsConfig[] => {
  return INSIGHTS_TEMPLATE.map(t => {
    let finalUrl = t.url
      .replace(/stockpk/g, pk)
      .replace(/symbol/g, symbol)
      .replace(/stockslugname/g, slug);

    return {
      ...t,
      url: finalUrl,
    };
  });
};

import React, { useState, useEffect } from 'react';
import { Lightbulb, Loader2, X, TrendingUp, TrendingDown, Minus, ExternalLink, RefreshCw, Search, CheckSquare, Square, Plus, Check } from 'lucide-react';
import { fetchPortfolioInsights } from '../../services/portfolioInsightsService';
import { PortfolioInsightCategory } from '../../types/portfolioInsightsTypes';
import { getTrackedItems, addTrackedItem, removeTrackedItem } from '../../services/trackingStorage';

interface PortfolioInsightsWidgetProps {
  onAddToMover: (symbol: string) => void;
  onNavigateStock?: (symbol: string, name: string) => void;
  addedSymbols?: string[];
  initialSymbolContext?: string; // If widget is opened from a specific stock row
}

const PortfolioInsightsWidget: React.FC<PortfolioInsightsWidgetProps> = ({ 
    onAddToMover,
    onNavigateStock,
    addedSymbols = [],
    initialSymbolContext
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [data, setData] = useState<PortfolioInsightCategory[]>([]);
  const [hasFetched, setHasFetched] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [trackedSet, setTrackedSet] = useState<Set<string>>(new Set());

  // Load tracked items and listen for updates
  useEffect(() => {
      const updateTracked = () => {
          const items = getTrackedItems().filter(i => i.type === 'STOCK');
          setTrackedSet(new Set(items.map(i => i.id)));
      };

      updateTracked();

      // Listen for global tracking updates
      window.addEventListener('fundflow_tracking_update', updateTracked);
      return () => window.removeEventListener('fundflow_tracking_update', updateTracked);
  }, []);

  // Lock body scroll when modal is open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      // If opened with context, set search query to that symbol initially
      if (initialSymbolContext) {
          setSearchQuery(initialSymbolContext);
      }
    } else {
      document.body.style.overflow = 'unset';
      setSearchQuery('');
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, initialSymbolContext]);

  const loadData = async () => {
      setIsLoading(true);
      try {
          const insights = await fetchPortfolioInsights();
          setData(insights);
          setHasFetched(true);
      } catch (error) {
          console.error("Failed to fetch portfolio insights", error);
      } finally {
          setIsLoading(false);
      }
  };

  const handleToggle = async (e: React.MouseEvent) => {
      e.stopPropagation();
      setIsOpen(true);
      if (!hasFetched) {
          await loadData();
      }
  };

  const handleRefresh = async () => {
      await loadData();
  };

  const handleTrackToggle = (e: React.MouseEvent, symbol: string) => {
      e.stopPropagation();
      if (trackedSet.has(symbol)) {
          removeTrackedItem(symbol, 'STOCK');
      } else {
          addTrackedItem({ id: symbol, name: symbol, symbol, type: 'STOCK' });
      }
  };

  const handleAddToMoverClick = (e: React.MouseEvent, symbol: string) => {
      e.stopPropagation();
      onAddToMover(symbol);
  };

  const handleNavigate = (e: React.MouseEvent, symbol: string) => {
      e.stopPropagation();
      if (onNavigateStock) {
          onNavigateStock(symbol, symbol);
          setIsOpen(false);
      }
  };

  // Filter data based on search query OR if specific symbol context is active, show matches
  const filteredData = data.map(category => ({
      ...category,
      items: category.items.filter(item => {
          if (searchQuery.trim()) {
              return item.symbol.toLowerCase().includes(searchQuery.toLowerCase()) ||
                     item.insightText.toLowerCase().includes(searchQuery.toLowerCase());
          }
          // Default: Show items that are in user's tracking list
          return trackedSet.has(item.symbol);
      })
  })).filter(cat => cat.items.length > 0);

  const getIcon = (type: string) => {
      if (type === 'positive') return <TrendingUp size={16} className="text-green-600" />;
      if (type === 'negative') return <TrendingDown size={16} className="text-red-600" />;
      return <Minus size={16} className="text-gray-400" />;
  };

  const activeCategoriesCount = filteredData.length;

  return (
    <>
        <button 
            onClick={handleToggle}
            className={`p-1.5 rounded-full hover:bg-indigo-50 text-gray-400 hover:text-indigo-600 transition-colors ${initialSymbolContext && trackedSet.has(initialSymbolContext) ? '' : ''}`}
            title="Check Insights"
        >
            <Lightbulb size={14} className={isOpen ? "fill-indigo-500 text-indigo-500" : ""} />
        </button>

        {isOpen && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in" onClick={() => setIsOpen(false)}>
                <div 
                    className="bg-white rounded-2xl shadow-2xl w-full max-w-3xl max-h-[85vh] flex flex-col overflow-hidden animate-scale-in border border-gray-200"
                    onClick={(e) => e.stopPropagation()}
                >
                    {/* Header */}
                    <div className="p-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between gap-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600">
                                <Lightbulb size={20} />
                            </div>
                            <div>
                                <h2 className="text-lg font-bold text-gray-900 leading-tight">Portfolio Updates</h2>
                                <p className="text-xs text-gray-500">Real-time alerts & activities matching your portfolio</p>
                            </div>
                        </div>

                        <div className="flex items-center gap-2">
                             <button 
                                onClick={handleRefresh}
                                disabled={isLoading}
                                className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-white rounded-lg transition-colors border border-transparent hover:border-gray-200"
                                title="Refresh Data"
                            >
                                <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
                            </button>
                            <button 
                                onClick={() => setIsOpen(false)}
                                className="p-2 text-gray-500 hover:text-gray-700 hover:bg-red-50 rounded-lg transition-colors"
                            >
                                <X size={20} />
                            </button>
                        </div>
                    </div>

                    {/* Search Bar & Tabs */}
                    <div className="p-4 border-b border-gray-100 bg-white sticky top-0 z-10 flex flex-col gap-3">
                        {/* Simple Category Tabs (Visual only for now since we load all) */}
                        <div className="flex gap-2 overflow-x-auto pb-1">
                            <span className="px-3 py-1 bg-indigo-600 text-white rounded-full text-xs font-bold whitespace-nowrap">Most Active</span>
                            <span className="px-3 py-1 bg-gray-100 text-gray-500 rounded-full text-xs font-medium whitespace-nowrap opacity-50 cursor-not-allowed">Price Spurts</span>
                            <span className="px-3 py-1 bg-gray-100 text-gray-500 rounded-full text-xs font-medium whitespace-nowrap opacity-50 cursor-not-allowed">Volume Spurts</span>
                            <span className="px-3 py-1 bg-gray-100 text-gray-500 rounded-full text-xs font-medium whitespace-nowrap opacity-50 cursor-not-allowed">Bulk Deals</span>
                        </div>

                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                            <input 
                                type="text"
                                placeholder="Search symbol to check activity..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                autoFocus
                            />
                        </div>
                    </div>

                    {/* Content */}
                    <div className="overflow-y-auto p-4 custom-scrollbar bg-gray-50/50 flex-1">
                        {isLoading ? (
                            <div className="flex flex-col items-center justify-center py-12 text-gray-400 gap-3">
                                <Loader2 size={32} className="animate-spin text-indigo-500" />
                                <span className="text-sm font-medium">Fetching Market Activities...</span>
                            </div>
                        ) : filteredData.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-12 text-gray-400 gap-2 text-center">
                                <Search size={32} className="opacity-20" />
                                {searchQuery ? (
                                    <p className="text-sm">No activity found for "{searchQuery}" in these categories.</p>
                                ) : (
                                    <>
                                        <p className="text-sm font-medium text-gray-600">No tracked stocks active in current categories.</p>
                                        <p className="text-xs text-gray-400">Search above or add more stocks to your watchlist.</p>
                                    </>
                                )}
                            </div>
                        ) : (
                            <div className="space-y-4">
                                {filteredData.map(category => (
                                    <div key={category.id} className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm flex flex-col">
                                        <div className="px-4 py-2 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                                            <h5 className="text-xs font-bold text-gray-600 uppercase tracking-wider">
                                                {category.title}
