                                <Lightbulb size={20} />
                            </div>
                            <div>
                                <h2 className="text-lg font-bold text-gray-900 leading-tight">Portfolio Updates</h2>
                                <p className="text-xs text-gray-500">Real-time alerts & activities matching your portfolio</p>
