       holdingsArray = holdingsRes;
    }

    const holdings: FundPortfolioHolding[] = Array.isArray(holdingsArray) 
      ? holdingsArray.map((item: any[]) => {
          const stockInfo = item[0] || {};
          return {
            stockName: stockInfo.name || "Unknown",
