// --- Proxy Helper ---

export const fetchFromProxy = async (url: string, options?: any): Promise<any> => {
  try {
      // Using a public CORS proxy for demonstration purposes. 
      // In production, this should route through your own backend.
      const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`;
      const response = await fetch(proxyUrl, options);

      if (!response.ok) {
        // Fallback or throw
        return null;
      }

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.includes("application/json")) {
          return await response.json();
      }
      return await response.text();
  } catch (error) {
      console.warn("Proxy Fetch Error (likely CORS or network):", error);
      return null;
  }
};

